window.onload = function() {
    renderCustomLeagueCheckboxes();
    
    const dbPicker = document.getElementById("league-db-picker");
    if(dbPicker) {
        dbPicker.addEventListener("change", function(e) {
            const val = e.target.value;
            const clc = document.getElementById("filters-container");
            if(val === "custom" || val === "mixed") {
                clc.style.display = "block";
                updateCustomDatabase();
            } else {
                clc.style.display = "none";
                let allSeasons = Object.keys(databases[val] || {});
                loadDatabase([val], allSeasons);
            }
        });
    }
    
    if(databases["TauronLiga"]) {
        loadDatabase(["TauronLiga"], Object.keys(databases["TauronLiga"]));
    }
    
    document.getElementById("btn-inst-next").onclick = function() { 
        document.getElementById("inst-modal").style.display = "none"; 
        document.getElementById("coach-modal").style.display = "flex"; 
        let inputName = document.getElementById("team-name-input").value; 
        if(inputName.trim() !== "") teamName = inputName;
        document.getElementById("team-display-name").innerText = teamName;
    };

    const btnSkip = document.getElementById("btn-skip"); if(btnSkip) btnSkip.onclick = skipTeam;
};

// Funkcja wywoływana z poziomu pierwszego okna
function initLanguage(lang) {
    document.getElementById('lang-modal').style.display = 'none';
    document.getElementById('inst-modal').style.display = 'flex';
    switchLanguage(lang);
}

// Globalny nasłuchiwacz na klawisz ENTER
document.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
        e.preventDefault();
        
        // Zbieramy główne przyciski akcji
        const btnInstNext = document.getElementById('btn-inst-next');
        const btnStartLeague = document.getElementById('btn-start-league-now');
        const btnNextMatch = document.getElementById('btn-next-match');
        const btnSetPause = document.getElementById('btn-next-set-continue');
        const btnReturnHub = document.getElementById('btn-return-hub');
        const btnRestart = document.getElementById('txt-sum-btn-restart');

        // Sprawdzamy który modal jest aktywny (offsetParent !== null) i klikamy
        if (btnInstNext && btnInstNext.offsetParent !== null) btnInstNext.click();
        else if (btnStartLeague && btnStartLeague.offsetParent !== null) btnStartLeague.click();
        else if (btnSetPause && btnSetPause.offsetParent !== null) btnSetPause.click();
        else if (btnReturnHub && btnReturnHub.offsetParent !== null) btnReturnHub.click();
        else if (btnNextMatch && btnNextMatch.offsetParent !== null) btnNextMatch.click();
        else if (btnRestart && btnRestart.offsetParent !== null) btnRestart.click();
    }
});

function renderCustomLeagueCheckboxes() {
    const container = document.getElementById("filters-container"); if(!container) return;
    let html = `<div class="filter-group"><div class="filter-group-title" id="filter-lg-title">Wybierz Ligi:</div>`;
    Object.keys(databases).forEach(dbKey => { html += `<label class="cb-label"><input type="checkbox" class="custom-league-cb" value="${dbKey}" checked> ${dbKey}</label>`; });
    html += `</div><div class="filter-group"><div class="filter-group-title" id="filter-sz-title">Wybierz Sezony:</div>`;
    
    let allSeasons = [];
    Object.keys(databases).forEach(lg => { Object.keys(databases[lg]).forEach(sz => { if(!allSeasons.includes(sz)) allSeasons.push(sz); }); });
    allSeasons.sort().reverse().forEach(sz => { html += `<label class="cb-label"><input type="checkbox" class="custom-season-cb" value="${sz}" checked> ${sz}</label>`; });
    html += `</div>`;
    
    container.innerHTML = html;
    document.querySelectorAll(".custom-league-cb").forEach(cb => { cb.addEventListener("change", updateCustomDatabase); });
    document.querySelectorAll(".custom-season-cb").forEach(cb => { cb.addEventListener("change", updateCustomDatabase); });
}

function updateCustomDatabase() {
    let selectedLg = []; document.querySelectorAll(".custom-league-cb:checked").forEach(c => selectedLg.push(c.value));
    let selectedSz = []; document.querySelectorAll(".custom-season-cb:checked").forEach(c => selectedSz.push(c.value));
    if(selectedLg.length === 0 || selectedSz.length === 0) { return; }
    loadDatabase(selectedLg, selectedSz);
}

function loadDatabase(leaguesArray, seasonsArray) { 
    activeDatabase = [];
    leaguesArray.forEach(lg => {
        if(databases[lg]) {
            seasonsArray.forEach(sz => {
                if(databases[lg][sz]) {
                    let teamsFromSeason = JSON.parse(JSON.stringify(databases[lg][sz])); 
                    teamsFromSeason.forEach(t => { 
                        if(!t.teamName.includes(sz.substring(2,7))) t.teamName += ` (${sz.substring(2,7)})`; 
                        activeDatabase.push(t);
                    });
                }
            });
        }
    });
    if(activeDatabase.length === 0 && databases["TauronLiga"] && databases["TauronLiga"]["2025/2026"]) {
         activeDatabase = JSON.parse(JSON.stringify(databases["TauronLiga"]["2025/2026"]));
    }
    availableTeams = [...activeDatabase]; rerollsLeft = 1; renderCoaches(); 
}

// === ZAZNACZ I PODMIEŃ OD TEGO MIEJSCA ===
function renderCoaches() {
    let availableCoaches = [];
    let selectedLg = []; 
    
    // Sprawdzenie, które ligi są zaznaczone w filtrach (własny mix)
    document.querySelectorAll(".custom-league-cb:checked").forEach(c => selectedLg.push(c.value));
    
    // Jeśli filtry są ukryte (np. na starcie), pobierz wartość z głównej listy wyboru
    if(selectedLg.length === 0) {
        let dbPicker = document.getElementById("league-db-picker");
        if(dbPicker && dbPicker.value !== "mixed" && dbPicker.value !== "custom") {
            selectedLg.push(dbPicker.value);
        } else {
            selectedLg = ["TauronLiga", "PlusLiga"]; // Tryb mieszany - obie ligi
        }
    }

    // Pobranie trenerów przypisanych do aktywnych lig
    selectedLg.forEach(lg => {
        if(coachesDB[lg]) availableCoaches = availableCoaches.concat(coachesDB[lg]);
    });
    
    // Zabezpieczenie przed duplikatami (usuwa powtórzenia w trybie mixed)
    availableCoaches = [...new Map(availableCoaches.map(item => [item.name, item])).values()];

    // Losowanie 3 opcji dla gracza
    let options = availableCoaches.sort(() => 0.5 - Math.random()).slice(0, 3);
    
    const container = document.getElementById("coach-options"); 
    if(!container) return; 
    container.innerHTML = "";
    
    // Pobranie aktualnego zestawu tłumaczeń na podstawie aktywnego języka gry
    let t = i18n[currentLang] || i18n["en"];
    
    options.forEach(coach => {
        const btn = document.createElement("div"); 
        btn.className = "coach-card";
        
        // Dynamiczne i bezpieczne tłumaczenie tekstu bonusu bez uszkadzania struktury obiektu trenera
        let translatedBonus = coach.bonusText
            .replace("Obrona", t.statObr ? t.statObr.replace(":", "") : "Obrona")
            .replace("Blok", t.statBlk ? t.statBlk.replace(":", "") : "Blok")
            .replace("Atak", t.statAtk ? t.statAtk.replace(":", "") : "Atak")
            .replace("Serwis", t.statSrv ? t.statSrv.replace(":", "") : "Serwis")
            .replace("Przyjęcie", t.statPrz ? t.statPrz.replace(":", "") : "Przyjęcie")
            .replace("Technika", t.statTec ? t.statTec.replace(":", "") : "Technika");

        btn.innerHTML = `<span style="font-size:1.1em;"><strong>${coach.name}</strong></span><span style="color: #00a8ff; font-size: 0.9em; text-align:center; margin-top:5px;">Bonus: ${translatedBonus}</span>`;
        btn.onclick = () => selectCoach(coach); 
        container.appendChild(btn);
    });
    
    const btnReroll = document.getElementById("btn-reroll");
    if(btnReroll) { 
        btnReroll.disabled = rerollsLeft <= 0; 
        btnReroll.style.backgroundColor = rerollsLeft <= 0 ? "#2f3640" : "#2c3e50"; 
        btnReroll.onclick = () => { 
            if (rerollsLeft > 0) { 
                rerollsLeft--; 
                renderCoaches(); 
                switchLanguage(currentLang); 
            } 
        }; 
    }
}
// === DO TEGO MIEJSCA WŁĄCZNIE ===

function selectCoach(selected) {
    currentCoach = selected; document.getElementById("current-trainer").innerText = currentCoach.name;
    document.getElementById("coach-modal").style.display = "none";
    drawNextTeam(); switchLanguage(currentLang);
}

function drawNextTeam() {
    if (availableTeams.length === 0) availableTeams = [...activeDatabase];
    const randomIndex = Math.floor(Math.random() * availableTeams.length); currentTeam = availableTeams[randomIndex]; availableTeams.splice(randomIndex, 1);
    const dtn = document.getElementById("drawn-team-name"); if(dtn) dtn.innerText = currentTeam.teamName;
    renderPlayers();
}

function renderPlayers() {
    const container = document.getElementById("available-players"); if(!container) return; container.innerHTML = ""; 
    const toggleOvr = document.getElementById("toggle-ovr");
    const showOvr = toggleOvr ? toggleOvr.checked : false;
    currentTeam.players.forEach(player => {
        const card = document.createElement("div");
        let tierClass = "card-bronze", badgeClass = "badge-bronze";
        if (player.OVR >= 85) { tierClass = "card-gold"; badgeClass = "badge-gold"; } else if (player.OVR >= 80) { tierClass = "card-silver"; badgeClass = "badge-silver"; }
        card.className = `player-card ${tierClass}`;
        
        let displayPos = getPosName(player.pos, currentLang);
        card.innerHTML = `<div class="ovr-badge ${badgeClass}" style="${showOvr ? '' : 'display:none;'}">${player.OVR}</div><div class="player-name">${player.name}</div><div class="player-pos">${displayPos}</div>`;

        let isSlotFilled = false;
        if (player.pos === "Rozgrywający" && myRoster["Rozgrywający"]) isSlotFilled = true;
        if (player.pos === "Atakujący" && myRoster["Atakujący"]) isSlotFilled = true;
        if (player.pos === "Libero" && myRoster["Libero"]) isSlotFilled = true;
        if (player.pos === "Przyjmujący" && myRoster["Przyjmujący1"] && myRoster["Przyjmujący2"]) isSlotFilled = true;
        if (player.pos === "Środkowy" && myRoster["Środkowy1"] && myRoster["Środkowy2"]) isSlotFilled = true;

        if (isSlotFilled) card.classList.add("disabled"); else card.onclick = () => pickPlayer(player);
        container.appendChild(card);
    });
}

function pickPlayer(player) {
    let assignedSlot = null;
    if (player.pos === "Rozgrywający" && !myRoster["Rozgrywający"]) assignedSlot = "Rozgrywający";
    else if (player.pos === "Atakujący" && !myRoster["Atakujący"]) assignedSlot = "Atakujący";
    else if (player.pos === "Libero" && !myRoster["Libero"]) assignedSlot = "Libero";
    else if (player.pos === "Przyjmujący") { if (!myRoster["Przyjmujący1"]) assignedSlot = "Przyjmujący1"; else if (!myRoster["Przyjmujący2"]) assignedSlot = "Przyjmujący2"; }
    else if (player.pos === "Środkowy") { if (!myRoster["Środkowy1"]) assignedSlot = "Środkowy1"; else if (!myRoster["Środkowy2"]) assignedSlot = "Środkowy2"; }

    if (assignedSlot) {
        myRoster[assignedSlot] = player; renderCourt(); updateTeamStats();
        if (Object.values(myRoster).every(slot => slot !== null)) {
            document.getElementById("available-players").innerHTML = `<button id="btn-start-league-now" class="btn-action" style="font-size: 1.1em; padding: 12px 30px; margin: 15px auto;">Start 🚀</button>`;
            document.getElementById("btn-skip").style.display = "none";
            document.getElementById("btn-start-league-now").onclick = function() { initializeSeason(); };
        } else { drawNextTeam(); }
    }
}

function renderCourt() {
    const slots = ["Rozgrywający", "Atakujący", "Przyjmujący1", "Przyjmujący2", "Środkowy1", "Środkowy2", "Libero"];
    slots.forEach(slotId => {
        const player = myRoster[slotId]; const slotEl = document.getElementById(`slot-${slotId}`); if(!slotEl) return;
        let posName = getPosName(slotId, currentLang); let emptyText = i18n[currentLang].emptySlot || "Puste";
        if (player) {
            slotEl.innerHTML = `${posName}<br><strong style="color: #00a8ff;">${player.name}</strong><br><span style="font-size: 0.8em;">OVR: ${player.OVR}</span>`;
            slotEl.style.backgroundColor = "rgba(46, 204, 113, 0.25)"; slotEl.style.borderColor = "#2ecc71";
        } else {
            slotEl.innerHTML = `${posName}<br><span>${emptyText}</span>`;
            if(slotId === "Libero") { slotEl.style.backgroundColor = "rgba(46, 204, 113, 0.2)"; slotEl.style.borderColor = "#2ecc71"; } 
            else if(slotId === "Środkowy2") { slotEl.style.backgroundColor = "rgba(0,0,0,0.6)"; slotEl.style.borderColor = "var(--glass-border)"; } 
            else { slotEl.style.backgroundColor = "rgba(0, 0, 0, 0.3)"; slotEl.style.borderColor = "var(--court-lines)"; }
        }
    });
}

function updateTeamStats() {
    let tOVR = 0, tATK = 0, tBLK = 0, tPRZ = 0, tOBR = 0, tZAG = 0, count = 0;
    for (let position in myRoster) { let p = myRoster[position]; if (p) { tOVR += p.OVR; tATK += p.ATK; tBLK += p.BLK; tPRZ += p.PRZ; tOBR += p.OBR; tZAG += p.ZAG; count++; } }
    if (count > 0) { safeSet("team-ovr", Math.round(tOVR / count)); safeSet("team-atk", Math.round(tATK / count)); safeSet("team-blk", Math.round(tBLK / count)); safeSet("team-prz", Math.round(tPRZ / count)); safeSet("team-obr", Math.round(tOBR / count)); safeSet("team-srv", Math.round(tZAG / count) + "%"); }
}

function skipTeam() {
    if (skipsLeft > 0) { skipsLeft--; drawNextTeam(); switchLanguage(currentLang); if (skipsLeft === 0) { document.getElementById("btn-skip").disabled = true; document.getElementById("btn-skip").style.backgroundColor = "#2f3640"; } }
}

// ============================================================================
// LIGA I PLAY-OFF
// ============================================================================
function getTeamAverageOVR(teamObj) {
    if(teamObj.isPlayer) return parseInt(document.getElementById("team-ovr").innerText) || 75;
    let total = 0; [...teamObj.originalRoster.players].sort((a,b) => b.OVR - a.OVR).slice(0,7).forEach(p => total += p.OVR);
    return Math.round(total / 7);
}

function initializeSeason() {
    season.teams = []; season.standings = {}; season.schedule = []; season.currentRound = 0; season.isPlayoffs = false; season.regularSeasonFinished = false; season.playerExitStage = null; season.champion = null;
    if (!season.bonusesApplied) {
        for (let pos in myRoster) {
            let p = myRoster[pos];
            if (p) {
                if (currentCoach.type === "DEF_BOOST" && (pos === "Libero" || pos.includes("Przyjmujący"))) p.OBR += currentCoach.value;
                if (currentCoach.type === "BLK_BOOST" && pos.includes("Środkowy")) p.BLK += currentCoach.value;
                if (currentCoach.type === "TEC_BOOST") p.TEC += currentCoach.value;
                if (currentCoach.type === "ATK_BOOST" && (pos === "Atakujący" || pos.includes("Przyjmujący"))) p.ATK += currentCoach.value;
                if (currentCoach.type === "SRV_BOOST") p.ZAG += currentCoach.value;
                if (currentCoach.type === "PRZ_BOOST" && (pos === "Libero" || pos.includes("Przyjmujący"))) p.PRZ += currentCoach.value;
            }
        }
        updateTeamStats(); season.bonusesApplied = true;
    }

    document.querySelector(".top-section").style.display = "none"; document.querySelector(".court-container").style.display = "none"; document.querySelector(".top-navbar").style.display = "none";
    let aiTeams = [...activeDatabase].sort(() => 0.5 - Math.random()).slice(0, 7);
    season.teams = [{ teamName: teamName, isPlayer: true, originalRoster: myRoster }];
    aiTeams.forEach(t => season.teams.push({ teamName: t.teamName, isPlayer: false, originalRoster: t }));
    season.teams.forEach(t => { t.avgOvr = getTeamAverageOVR(t); season.standings[t.teamName] = { pts: 0, w: 0, l: 0, setsW: 0, setsL: 0 }; });

    let n = 8, tIds = [0, 1, 2, 3, 4, 5, 6, 7];
    for (let round = 0; round < n - 1; round++) { let roundMatches = []; for (let i = 0; i < n / 2; i++) roundMatches.push([ tIds[i], tIds[n - 1 - i] ]); season.schedule.push(roundMatches); tIds.splice(1, 0, tIds.pop()); }
    showSeasonHub();
}

function showSeasonHub() {
    document.getElementById("season-hub-modal").style.display = "flex";
    if(season.isPlayoffs) {
        safeSet("season-hub-title", i18n[currentLang].playoffTitle); safeSet("season-round-info", "Play-Off"); renderPlayoffHub();
    } else {
        if (season.currentRound === 7) {
            safeSet("season-round-info", "Koniec Sezonu");
            document.getElementById("btn-next-match").innerText = "Play-Off 🏆"; document.getElementById("btn-next-match").onclick = setupPlayoffs;
        } else {
            safeSet("season-round-info", `${i18n[currentLang].roundInfo}: ${season.currentRound + 1} / 7`);
            document.getElementById("btn-next-match").innerText = i18n[currentLang].btnNextMatch; document.getElementById("btn-next-match").onclick = playLeagueRound;
        }
        renderLeagueTable();
    }
}

function renderLeagueTable() {
    let st = Object.keys(season.standings).map(key => ({ name: key, data: season.standings[key] }));
    st.sort((a, b) => { if(b.data.pts !== a.data.pts) return b.data.pts - a.data.pts; let aRatio = a.data.setsL === 0 ? a.data.setsW : a.data.setsW / a.data.setsL; let bRatio = b.data.setsL === 0 ? b.data.setsW : b.data.setsW / b.data.setsL; return bRatio - aRatio; });
    const tbody = document.getElementById("standings-body"); tbody.innerHTML = "";
    st.forEach((t, index) => { let tr = document.createElement("tr"); if(t.name === teamName) tr.className = "my-team-row"; tr.innerHTML = `<td>${index + 1}</td><td style="text-align: left;">${t.name}</td><td><strong>${t.data.pts}</strong></td><td>${t.data.w}</td><td>${t.data.l}</td><td>${t.data.setsW}</td><td>${t.data.setsL}</td>`; tbody.appendChild(tr); });
}

function playLeagueRound() {
    let matches = season.schedule[season.currentRound]; document.getElementById("season-hub-modal").style.display = "none";
    matches.forEach(matchInfo => {
        let t1 = season.teams[matchInfo[0]], t2 = season.teams[matchInfo[1]];
        if (t1.isPlayer || t2.isPlayer) { season.myCurrentOpponent = t1.isPlayer ? t2 : t1; setupPlayerMatch(season.myCurrentOpponent); } 
        else { let result = fastSimulateAIMatch(t1, t2); updateStandings(t1.teamName, t2.teamName, result.s1, result.s2); }
    });
}

function fastSimulateAIMatch(t1, t2) {
    let probT1 = Math.max(0.15, Math.min(0.85, 0.5 + ((t1.avgOvr - t2.avgOvr) * 0.025))); let s1 = 0, s2 = 0;
    while(s1 < 3 && s2 < 3) { if(Math.random() < probT1) s1++; else s2++; } return { s1: s1, s2: s2 };
}

function updateStandings(name1, name2, sets1, sets2) {
    let st1 = season.standings[name1], st2 = season.standings[name2]; st1.setsW += sets1; st1.setsL += sets2; st2.setsW += sets2; st2.setsL += sets1;
    if (sets1 === 3) { st1.w++; st2.l++; if (sets2 <= 1) st1.pts += 3; else st1.pts += 2; if(sets2===2) st2.pts += 1; } else { st2.w++; st1.l++; if (sets1 <= 1) st2.pts += 3; else st2.pts += 2; if(sets1===2) st1.pts += 1; }
}

// ============================================================================
// SYSTEM TAKTYK I SILNIK MECZOWY Z BLOKADAMI
// ============================================================================
function setTacticState(enabled) {
    document.querySelectorAll(".tactic-btn").forEach(btn => btn.disabled = !enabled);
}

function setTactic(tacticName) {
    if (isMatchPlaying) return; 
    myTactic = tacticName;
    document.querySelectorAll(".tactic-btn").forEach(btn => btn.classList.remove("active"));
    if(tacticName === "OFENSYWA") document.getElementById("btn-tac-ofensywa").classList.add("active");
    if(tacticName === "DEFENSYWA") document.getElementById("btn-tac-defensywa").classList.add("active");
    if(tacticName === "KONTROLA") document.getElementById("btn-tac-kontrola").classList.add("active");
}

function applyTacticBoost(baseStat, actionType, isMe) {
    let activeTactic = isMe ? myTactic : oppTactic;
    if (activeTactic === "OFENSYWA" && (actionType === "ATK" || actionType === "ZAG") && Math.random() < 0.70) return baseStat + Math.floor(Math.random() * 4) + 1;
    if (activeTactic === "DEFENSYWA" && (actionType === "BLK" || actionType === "OBR" || actionType === "PRZ") && Math.random() < 0.70) return baseStat + Math.floor(Math.random() * 4) + 1;
    if (activeTactic === "KONTROLA" && actionType === "TEC" && Math.random() < 0.70) return baseStat + Math.floor(Math.random() * 4) + 1;
    return baseStat;
}

function setupPlayerMatch(opponent) {
    for (let pos in myRoster) { let p = myRoster[pos]; if (p) matchStats[p.name] = { name: p.name, pos: p.pos, ptsTot: 0, ptsBP: 0, wl: 0, srvTot: 0, srvErr: 0, srvAce: 0, przTot: 0, przErr: 0, przExc: 0, przPoz: 0, atkTot: 0, atkErr: 0, atkBlk: 0, atkPkt: 0, blkPkt: 0 }; }
    mySets = 0; oppSets = 0; myScore = 0; oppScore = 0; matchFinished = false; tacticalTimeout.available = true; isMatchPlaying = false; isSetPaused = false;
    
    let tacticsArr = ["OFENSYWA", "DEFENSYWA", "KONTROLA"]; oppTactic = tacticsArr[Math.floor(Math.random() * tacticsArr.length)];
    
    safeSet("final-my-team", teamName); safeSet("opponent-name-final", opponent.teamName);
    document.getElementById("result-modal").style.display = "flex"; document.getElementById("btn-return-hub").style.display = "none";
    document.getElementById("time-controls").style.display = "flex"; document.getElementById("tactics-container").style.display = "flex";
    document.getElementById("set-pause-container").style.display = "none"; document.getElementById("btn-timeout-trigger").disabled = true;
    setTacticState(true); 
    
    safeSet("score-my", "0"); safeSet("score-opp", "0"); safeSet("sets-my", "0"); safeSet("sets-opp", "0");
    safeSet("play-by-play", "<span style='color:#bdc3c7;'>Wybierz taktykę i uruchom silnik meczowy!</span><br>", true);
    
    renderStatsTable();
}

function callTimeout() {
    if (!tacticalTimeout.available || matchFinished || !isMatchPlaying) return;
    tacticalTimeout.available = false; document.getElementById("btn-timeout-trigger").disabled = true;
    const logDiv = document.getElementById("play-by-play");

    clearInterval(matchInterval); isMatchPlaying = false; setTacticState(true); 
    document.getElementById("set-pause-container").style.display = "block";
    safeSet("txt-set-pause-msg", i18n[currentLang].timeoutPauseMsg);
    
    document.getElementById("btn-next-set-continue").innerText = i18n[currentLang].btnResumeMatch;
    document.getElementById("btn-next-set-continue").onclick = function() {
        document.getElementById("set-pause-container").style.display = "none";
        if (Math.random() < 0.75) {
            tacticalTimeout.active = true; tacticalTimeout.pointsRemaining = Math.floor(Math.random() * 4) + 2;
            const stats = ["ATK", "BLK", "OBR", "PRZ", "ZAG"]; tacticalTimeout.boostedStat = stats[Math.floor(Math.random() * stats.length)]; tacticalTimeout.boostValue = Math.floor(Math.random() * 5) + 1;
            logDiv.innerHTML = `<span style="color:#00a8ff; font-weight:bold;">⏱ Bonus +${tacticalTimeout.boostValue} do ${tacticalTimeout.boostedStat} na ${tacticalTimeout.pointsRemaining} akcje!</span><br>` + logDiv.innerHTML;
        } else { logDiv.innerHTML = `<span style="color:#e74c3c;">⏱ Brak bonusu taktycznego.</span><br>` + logDiv.innerHTML; }
        
        startMatchLoop(); 
    };
}
function playSinglePoint() {
    let pointForMe = false, actionLog = "";
    const myPlayersArr = Object.values(myRoster).filter(p => p !== null);
    let oppOVR = season.myCurrentOpponent ? season.myCurrentOpponent.avgOvr : 75;

    // Bezpieczne pobieranie statystyk, nawet gdy panel jest ukryty (textContent)
    let elBlk = document.getElementById("team-blk"), elObr = document.getElementById("team-obr");
    let baseBlk = elBlk ? parseInt(elBlk.textContent) || 50 : 50;
    let baseObr = elObr ? parseInt(elObr.textContent) || 50 : 50;

    baseBlk = applyTacticBoost(baseBlk, "BLK", true); 
    baseObr = applyTacticBoost(baseObr, "OBR", true);

    if (tacticalTimeout.active && tacticalTimeout.pointsRemaining > 0) {
        if (tacticalTimeout.boostedStat === "BLK") baseBlk += tacticalTimeout.boostValue;
        if (tacticalTimeout.boostedStat === "OBR") baseObr += tacticalTimeout.boostValue;
    }
    let teamBlk = baseBlk / 100, teamObr = baseObr / 100;

    try {
        if (isMyServe) {
            let servers = myPlayersArr.filter(p => p.pos !== "Libero");
            let server = servers[Math.floor(Math.random() * servers.length)] || myPlayersArr[0];
            let sStats = matchStats[server.name]; if(sStats) sStats.srvTot++;
            let serverZAG = applyTacticBoost(server.ZAG, "ZAG", true); 
            if (tacticalTimeout.active && tacticalTimeout.boostedStat === "ZAG") serverZAG += tacticalTimeout.boostValue;

            let srvRoll = Math.random() * 100;
            if (srvRoll < (serverZAG / 9)) { if(sStats){ sStats.srvAce++; sStats.ptsTot++; sStats.ptsBP++; sStats.wl++; } actionLog = `AS SERWISOWY! ${server.name} punktuje!`; pointForMe = true; } 
            else if (srvRoll > (100 - (100 - serverZAG) / 3)) { if(sStats){ sStats.srvErr++; sStats.wl--; } actionLog = `Błąd zagrywki. ${server.name} w siatkę.`; pointForMe = false; } 
            else {
                let roll = Math.random(), blockChance = 0.08 + (teamBlk * 0.06), oppErrorChance = 0.09 - ((oppOVR - 75) * 0.001);
                if (roll < blockChance) { 
                    let middles = myPlayersArr.filter(p => p.pos && p.pos.includes("Środkowy"));
                    let blocker = middles.length > 0 && Math.random() < 0.65 ? middles[Math.floor(Math.random() * middles.length)] : myPlayersArr.filter(p => p.pos !== "Libero")[Math.floor(Math.random() * myPlayersArr.filter(p => p.pos !== "Libero").length)];
                    if(!blocker) blocker = myPlayersArr[0];
                    if(matchStats[blocker.name]) { matchStats[blocker.name].blkPkt++; matchStats[blocker.name].ptsTot++; matchStats[blocker.name].ptsBP++; matchStats[blocker.name].wl++; }
                    actionLog = `MONSTER BLOK! ${blocker.name} zatrzymuje atak!`; pointForMe = true;
                } else if (roll < blockChance + oppErrorChance) { actionLog = `Przeciwnik atakuje w aut! Punkt dla nas.`; pointForMe = true;
                } else if (roll < 0.52 + ((oppOVR/100) * 0.05)) { actionLog = `Rywalki skutecznie kończą akcję.`; pointForMe = false;
                } else { 
                    let rollAtk = Math.random(), attacker;
                    let atakujacy = myPlayersArr.filter(p => p.pos === "Atakujący"), przyjmujacy = myPlayersArr.filter(p => p.pos && p.pos.includes("Przyjmujący")), srodkowi = myPlayersArr.filter(p => p.pos && p.pos.includes("Środkowy"));
                    if (rollAtk < 0.60 && przyjmujacy.length > 0) attacker = przyjmujacy[Math.floor(Math.random() * przyjmujacy.length)];
                    else if (rollAtk < 0.90 && atakujacy.length > 0) attacker = atakujacy[0];
                    else if (srodkowi.length > 0) attacker = srodkowi[Math.floor(Math.random() * srodkowi.length)];
                    else attacker = myPlayersArr.filter(p => p.pos !== "Libero" && p.pos !== "Rozgrywający")[0] || myPlayersArr[0];

                    let aStats = matchStats[attacker.name]; if(aStats) aStats.atkTot++;
                    let attackerATK = applyTacticBoost(attacker.ATK, "ATK", true); let attackerTEC = applyTacticBoost(attacker.TEC, "TEC", true);
                    if (tacticalTimeout.active && tacticalTimeout.boostedStat === "ATK") attackerATK += tacticalTimeout.boostValue;
                    if (tacticalTimeout.active && tacticalTimeout.boostedStat === "TEC") attackerTEC += tacticalTimeout.boostValue;

                    let atkPower = (attackerATK * 0.55 + attackerTEC * 0.45) / 100; let counterRoll = Math.random();
                    if (counterRoll < (atkPower * 0.48)) { if(aStats){ aStats.atkPkt++; aStats.ptsTot++; aStats.ptsBP++; aStats.wl++; } actionLog = `Obrona i kontra! ${attacker.name} punktuje!`; pointForMe = true; } 
                    else if (counterRoll > 0.85) { if(aStats){ aStats.atkErr++; aStats.wl--; } actionLog = `Kontra w aut. ${attacker.name} się myli.`; pointForMe = false; } 
                    else if (counterRoll > 0.75) { if(aStats){ aStats.atkBlk++; aStats.wl--; } actionLog = `Atak z kontry zablokowany.`; pointForMe = false; } 
                    else { actionLog = `Przeciwniczki bronią naszą kontrę.`; pointForMe = false; }
                }
            }
        } else { 
            let srvRollOpp = Math.random() * 100, oppAceChance = 4 + ((oppOVR - 75) * 0.15), oppErrChance = 8 - ((oppOVR - 75) * 0.1);
            if (oppTactic === "OFENSYWA") { oppAceChance += 1; } if (oppTactic === "KONTROLA") { oppErrChance -= 1; }

            if (srvRollOpp < oppAceChance) { 
                let receivers = myPlayersArr.filter(p => p.pos === "Libero" || (p.pos && p.pos.includes("Przyjmujący")));
                let receiver = receivers[Math.floor(Math.random() * receivers.length)] || myPlayersArr[0];
                if(matchStats[receiver.name]) { matchStats[receiver.name].przTot++; matchStats[receiver.name].przErr++; matchStats[receiver.name].wl--; }
                actionLog = `As serwisowy rywalek. ${receiver.name} zaskoczona.`; pointForMe = false;
            } else if (srvRollOpp > 100 - oppErrChance) { actionLog = `Błąd na zagrywce po stronie rywalek.`; pointForMe = true;
            } else { 
                let receivers = myPlayersArr.filter(p => p.pos === "Libero" || (p.pos && p.pos.includes("Przyjmujący")));
                let receiver = receivers[Math.floor(Math.random() * receivers.length)] || myPlayersArr[0];
                let rStats = matchStats[receiver.name]; if(rStats) rStats.przTot++;
                let receiverPRZ = applyTacticBoost(receiver.PRZ, "PRZ", true); if (tacticalTimeout.active && tacticalTimeout.boostedStat === "PRZ") receiverPRZ += tacticalTimeout.boostValue;

                let passRoll = Math.random() * 100, perfectPass = false;
                if (passRoll < receiverPRZ) { if(rStats){ rStats.przExc++; rStats.przPoz++; } perfectPass = true; } else if (passRoll < receiverPRZ + 20) { if(rStats) rStats.przPoz++; }

                let rollAtk = Math.random(), attacker;
                let atakujacy = myPlayersArr.filter(p => p.pos === "Atakujący"), przyjmujacy = myPlayersArr.filter(p => p.pos && p.pos.includes("Przyjmujący")), srodkowi = myPlayersArr.filter(p => p.pos && p.pos.includes("Środkowy"));
                let srodkowySzansa = perfectPass ? 0.35 : 0.10; 
                
                if (rollAtk < srodkowySzansa && srodkowi.length > 0) attacker = srodkowi[Math.floor(Math.random() * srodkowi.length)];
                else if (rollAtk < srodkowySzansa + 0.35 && atakujacy.length > 0) attacker = atakujacy[0];
                else if (przyjmujacy.length > 0) attacker = przyjmujacy[Math.floor(Math.random() * przyjmujacy.length)];
                else attacker = myPlayersArr.filter(p => p.pos !== "Libero" && p.pos !== "Rozgrywający")[0] || myPlayersArr[0];

                let aStats = matchStats[attacker.name]; if(aStats) aStats.atkTot++;
                let attackerATK = applyTacticBoost(attacker.ATK, "ATK", true); let attackerTEC = applyTacticBoost(attacker.TEC, "TEC", true);
                if (tacticalTimeout.active && tacticalTimeout.boostedStat === "ATK") attackerATK += tacticalTimeout.boostValue;
                if (tacticalTimeout.active && tacticalTimeout.boostedStat === "TEC") attackerTEC += tacticalTimeout.boostValue;

                let myAtkPower = (attackerATK * 0.55 + attackerTEC * 0.45) / 100; if (perfectPass) myAtkPower *= 1.25; 

                let myAtkRoll = Math.random(), killChance = myAtkPower * 0.53; 
                if (myAtkRoll < killChance) { if(aStats){ aStats.atkPkt++; aStats.ptsTot++; aStats.wl++; } actionLog = `Udany atak z pierwszej piłki! ${attacker.name} punktuje!`; pointForMe = true; } 
                else if (myAtkRoll > 0.86) { if(aStats){ aStats.atkErr++; aStats.wl--; } actionLog = `Atak w siatkę. ${attacker.name} popełnia błąd.`; pointForMe = false; } 
                else if (myAtkRoll > 0.75) { if(aStats){ aStats.atkBlk++; aStats.wl--; } actionLog = `${attacker.name} zatrzymana na podwójnym bloku!`; pointForMe = false; } 
                else { 
                    if (Math.random() < (teamObr * 0.38)) { 
                        if (Math.random() < 0.6) { if(aStats){ aStats.atkPkt++; aStats.ptsTot++; aStats.wl++; } actionLog = `Obroniony atak i skuteczna kontra (${attacker.name})!`; pointForMe = true; } 
                        else { actionLog = `Długa wymiana kończy się punktem dla przeciwnika.`; pointForMe = false; }
                    } else { actionLog = `Przeciwnik kontratakuje bezbłędnie.`; pointForMe = false; }
                }
            }
        }
    } catch(e) { console.error("Silnik wylosował anomalię:", e); pointForMe = Math.random() > 0.5; actionLog = "Mocna akcja!"; }

    if (tacticalTimeout.active) { tacticalTimeout.pointsRemaining--; if (tacticalTimeout.pointsRemaining <= 0) tacticalTimeout.active = false; }
    if (pointForMe) { myScore++; isMyServe = true; } else { oppScore++; isMyServe = false; }
    return { pointForMe, actionLog };
}

function checkSetAndMatch(logDiv) {
    let targetScore = (mySets + oppSets === 4) ? 15 : 25; 
    if ((myScore >= targetScore || oppScore >= targetScore) && Math.abs(myScore - oppScore) >= 2) {
        if (myScore > oppScore) { mySets++; logDiv.innerHTML = `<span style="color: #00a8ff; font-weight:bold;">*** SET WYGRANY (${myScore}:${oppScore}) ***</span><br>` + logDiv.innerHTML; } 
        else { oppSets++; logDiv.innerHTML = `<span style="color: #e74c3c; font-weight:bold;">*** SET PRZEGRANY (${myScore}:${oppScore}) ***</span><br>` + logDiv.innerHTML; }
        myScore = 0; oppScore = 0; safeSet("sets-my", mySets); safeSet("sets-opp", oppSets);

        let tacticsArr = ["OFENSYWA", "DEFENSYWA", "KONTROLA"]; oppTactic = tacticsArr[Math.floor(Math.random() * tacticsArr.length)];

        if (mySets === 3 || oppSets === 3) {
            matchFinished = true; isMatchPlaying = false; renderStatsTable();
            try { document.getElementById("time-controls").style.display = "none"; document.getElementById("tactics-container").style.display = "none";
            document.getElementById("btn-return-hub").style.display = "block"; document.getElementById("set-pause-container").style.display = "none"; } catch(e){}
            logDiv.innerHTML = `<strong style="font-size: 1.2em; color: ${mySets===3 ? '#2ecc71' : '#e74c3c'};">KONIEC MECZU. Wynik: ${mySets}:${oppSets}</strong><br>` + logDiv.innerHTML;
            return true; 
        } else {
            clearInterval(matchInterval); isMatchPlaying = false; setTacticState(true);
            try { document.getElementById("set-pause-container").style.display = "block"; document.getElementById("btn-timeout-trigger").disabled = true; } catch(e){}
            safeSet("txt-set-pause-msg", i18n[currentLang].setPauseMsg);
            let btnCont = document.getElementById("btn-next-set-continue");
            if(btnCont) {
                btnCont.innerText = i18n[currentLang].btnNextSetCont;
                btnCont.onclick = function() {
                    document.getElementById("set-pause-container").style.display = "none";
                    tacticalTimeout.available = true; document.getElementById("btn-timeout-trigger").disabled = false;
                    startMatchLoop();
                };
            }
            return true;
        }
    }
    return false; 
}

function startMatchLoop() {
    if (matchInterval) clearInterval(matchInterval);
    isMatchPlaying = true; setTacticState(false); 
    document.getElementById("btn-timeout-trigger").disabled = !tacticalTimeout.available;
    const logDiv = document.getElementById("play-by-play");
    matchInterval = setInterval(() => {
        if (matchFinished || !isMatchPlaying) { clearInterval(matchInterval); return; }
        let result = playSinglePoint(); let color = result.pointForMe ? "#2ecc71" : "#e74c3c";
        logDiv.innerHTML = `<span style="color: ${color};">[${myScore}:${oppScore}] ${result.actionLog}</span><br>` + logDiv.innerHTML;
        let lines = logDiv.innerHTML.split('<br>'); if (lines.length > 25) logDiv.innerHTML = lines.slice(0, 25).join('<br>');
        safeSet("score-my", myScore); safeSet("score-opp", oppScore);
        renderStatsTable(); checkSetAndMatch(logDiv);
    }, currentSpeed);
}

function changeSpeed(ms) { if(matchFinished) return; currentSpeed = ms; startMatchLoop(); }

function instantSimulation() {
    if(matchFinished) return; 
    if(matchInterval) clearInterval(matchInterval);
    isMatchPlaying = true; setTacticState(false); 
    let pauseCont = document.getElementById("set-pause-container"); if(pauseCont) pauseCont.style.display = "none";
    const logDiv = document.getElementById("play-by-play");
    if(logDiv) logDiv.innerHTML = `<strong>-- GENEROWANIE WYNIKU --</strong><br>` + logDiv.innerHTML;
    
    // Zabezpieczenie przed nieskończoną pętlą (hard stop przy max ilości piłek)
    let safetyCounter = 0; 

    try {
        while (!matchFinished && safetyCounter < 500) { 
            safetyCounter++;
            if (tacticalTimeout.available && Math.random() < 0.15) { 
                tacticalTimeout.available = false; tacticalTimeout.active = true; tacticalTimeout.pointsRemaining = Math.floor(Math.random() * 4) + 2;
                const stats = ["ATK", "BLK", "OBR", "PRZ", "ZAG"]; tacticalTimeout.boostedStat = stats[Math.floor(Math.random() * stats.length)]; tacticalTimeout.boostValue = Math.floor(Math.random() * 5) + 1;
            }
            playSinglePoint(); 
            let targetScore = (mySets + oppSets === 4) ? 15 : 25; 
            if ((myScore >= targetScore || oppScore >= targetScore) && Math.abs(myScore - oppScore) >= 2) {
                if (myScore > oppScore) mySets++; else oppSets++; myScore = 0; oppScore = 0; tacticalTimeout.available = true;
                let tacticsArr = ["OFENSYWA", "DEFENSYWA", "KONTROLA"]; oppTactic = tacticsArr[Math.floor(Math.random() * tacticsArr.length)];
                if (mySets === 3 || oppSets === 3) matchFinished = true;
            }
        }
    } catch(err) {
        console.error("Symulacja awaryjna:", err);
        matchFinished = true; mySets = 3; oppSets = 0; // W razie skrajnego błędu gracz wygrywa, żeby nie blokować sezonu
    }

    safeSet("score-my", myScore); safeSet("score-opp", oppScore); safeSet("sets-my", mySets); safeSet("sets-opp", oppSets);
    renderStatsTable(); 
    isMatchPlaying = false;
    
    // Gwarantowane ukrycie UI i wyświetlenie przycisku powrotu
    try {
        let tc = document.getElementById("time-controls"); if(tc) tc.style.display = "none"; 
        let tac = document.getElementById("tactics-container"); if(tac) tac.style.display = "none"; 
        let ret = document.getElementById("btn-return-hub"); if(ret) ret.style.display = "block";
    } catch(e) {}
    
    if(logDiv) logDiv.innerHTML = `<strong style="font-size: 1.2em; color: ${mySets===3 ? '#2ecc71' : '#e74c3c'};">KONIEC MECZU. Wynik: ${mySets}:${oppSets}</strong><br>` + logDiv.innerHTML;
}

function renderStatsTable() {
    try {
        const tbody = document.getElementById("stats-table-body"); 
        if(!tbody) return;
        tbody.innerHTML = "";
        for (let p in matchStats) {
            let s = matchStats[p];
            if(!s || !s.pos) continue; // Pancerne zabezpieczenie

            let przPozPct = s.przTot > 0 ? Math.round((s.przPoz / s.przTot) * 100 * 0.65) + "%" : "-"; 
            let przExcPct = s.przTot > 0 ? Math.round((s.przExc / s.przTot) * 100 * 0.4) + "%" : "-"; 
            let atkExcPct = s.atkTot > 0 ? Math.round((s.atkPkt / s.atkTot) * 100) + "%" : "-"; 
            let atkEffPct = s.atkTot > 0 ? Math.round(((s.atkPkt - s.atkErr - s.atkBlk) / s.atkTot) * 100) + "%" : "-"; 
            let wlColor = s.wl > 0 ? "#2ecc71" : (s.wl < 0 ? "#e74c3c" : "#ecf0f1");
            
            let pName = getPosName(s.pos, currentLang);

            tbody.innerHTML += `<tr>
                <td style="font-weight: bold; font-size:0.95em; text-align:left;">${s.name}<br><span style="font-size:0.7em; color:#bdc3c7; font-weight:normal;">${pName}</span></td>
                <td><strong style="color:white;">${s.ptsTot}</strong> | <span style="color:#bdc3c7;">${s.ptsBP}</span> | <span style="color: ${wlColor}; font-weight: bold;">${s.wl > 0 ? '+'+s.wl : s.wl}</span></td>
                <td><span style="color:#bdc3c7;">${s.srvTot} | ${s.srvErr}</span> | <strong style="color:#00a8ff;">${s.srvAce}</strong></td>
                <td><span style="color:#bdc3c7;">${s.przTot} | ${s.przErr}</span> | <strong style="color:#a29bfe;">${przPozPct}</strong> | <strong style="color:#2ecc71;">${przExcPct}</strong></td>
                <td><span style="color:#bdc3c7;">${s.atkTot} | ${s.atkErr} | ${s.atkBlk}</span> | <strong style="color:#2ecc71;">${s.atkPkt}</strong> | ${atkExcPct} | <strong>${atkEffPct}</strong></td>
                <td><strong style="color:#e67e22;">${s.blkPkt}</strong></td>
            </tr>`;
        }
    } catch (e) {
        console.error("Błąd tabeli:", e);
    }
}

function updateSeasonStats() {
    for (let p in matchStats) {
        if (!seasonStats[p]) { seasonStats[p] = JSON.parse(JSON.stringify(matchStats[p])); } 
        else {
            seasonStats[p].ptsTot += matchStats[p].ptsTot; seasonStats[p].ptsBP += matchStats[p].ptsBP; seasonStats[p].wl += matchStats[p].wl; seasonStats[p].srvTot += matchStats[p].srvTot; seasonStats[p].srvErr += matchStats[p].srvErr; seasonStats[p].srvAce += matchStats[p].srvAce; seasonStats[p].przTot += matchStats[p].przTot; seasonStats[p].przErr += matchStats[p].przErr; seasonStats[p].przPoz += matchStats[p].przPoz; seasonStats[p].przExc += matchStats[p].przExc; seasonStats[p].atkTot += matchStats[p].atkTot; seasonStats[p].atkErr += matchStats[p].atkErr; seasonStats[p].atkBlk += matchStats[p].atkBlk; seasonStats[p].atkPkt += matchStats[p].atkPkt; seasonStats[p].blkPkt += matchStats[p].blkPkt;
        }
    }
}

function returnToSeasonHub() {
    updateSeasonStats(); document.getElementById("result-modal").style.display = "none"; document.getElementById("tactics-container").style.display = "flex"; setTacticState(true);
    if(!season.isPlayoffs) {
        updateStandings(teamName, season.myCurrentOpponent.teamName, mySets, oppSets); season.currentRound++;
        if (season.currentRound === 7 && !season.regularSeasonFinished) { season.regularSeasonFinished = true; showSeasonHub(); } 
        else if (season.currentRound > 7 || (season.currentRound === 7 && season.regularSeasonFinished)) { setupPlayoffs(); } 
        else { showSeasonHub(); }
    } else { processPlayoffResult(); }
}

function setupPlayoffs() {
    season.isPlayoffs = true; season.playoffStage = "ĆWIERĆFINAŁY";
    let st = Object.keys(season.standings).map(key => ({ name: key, data: season.standings[key] }));
    st.sort((a, b) => { if(b.data.pts !== a.data.pts) return b.data.pts - a.data.pts; let aRatio = a.data.setsL === 0 ? a.data.setsW : a.data.setsW / a.data.setsL; let bRatio = b.data.setsL === 0 ? b.data.setsW : b.data.setsW / b.data.setsL; return bRatio - aRatio; });
    let top8 = st.map(t => t.name);

    season.bracket = {
        qf: [ { id: "QF1", t1: top8[0], t2: top8[7], wins1: 0, wins2: 0, finished: false, winner: "TBD" }, { id: "QF2", t1: top8[3], t2: top8[4], wins1: 0, wins2: 0, finished: false, winner: "TBD" }, { id: "QF3", t1: top8[1], t2: top8[6], wins1: 0, wins2: 0, finished: false, winner: "TBD" }, { id: "QF4", t1: top8[2], t2: top8[5], wins1: 0, wins2: 0, finished: false, winner: "TBD" } ],
        sf: [ { id: "SF1", t1: "TBD", t2: "TBD", wins1: 0, wins2: 0, finished: false, winner: "TBD", loser: "TBD" }, { id: "SF2", t1: "TBD", t2: "TBD", wins1: 0, wins2: 0, finished: false, winner: "TBD", loser: "TBD" } ],
        finals: [ { id: "3P", t1: "TBD", t2: "TBD", wins1: 0, wins2: 0, finished: false, winner: "TBD", isThirdPlace: true }, { id: "F", t1: "TBD", t2: "TBD", wins1: 0, wins2: 0, finished: false, winner: "TBD", isFinal: true } ]
    };
    season.playoffMatchups = season.bracket.qf; showSeasonHub();
}

function drawBracketMatch(m) {
    let isMyMatch = (m.t1 === teamName || m.t2 === teamName), activeStage = season.playoffMatchups.some(p => p.id === m.id);
    let borderCol = isMyMatch ? "#2ecc71" : "#2c2c54", bgCol = isMyMatch ? "rgba(108, 92, 231, 0.15)" : "#16162d";
    if (activeStage && !m.finished) { borderCol = "#00a8ff"; if(isMyMatch) bgCol = "#192a56"; }
    return `<div class="bracket-match" style="border-color: ${borderCol}; background-color: ${bgCol};"><div class="bracket-team ${m.wins1 === 2 ? 'winner' : ''}"><span>${m.t1.substring(0,15)}</span><span class="bracket-score">${m.wins1}</span></div><div class="bracket-team ${m.wins2 === 2 ? 'winner' : ''}"><span>${m.t2.substring(0,15)}</span><span class="bracket-score">${m.wins2}</span></div></div>`;
}

function renderPlayoffHub() {
    document.getElementById("table-container").style.display = "none"; const infoDiv = document.getElementById("playoff-info"); infoDiv.style.display = "block";
    infoDiv.innerHTML = `<h3 style="font-size: 1.4em; color: #00a8ff; text-transform: uppercase;">FAZA PUCHAROWA: ${season.playoffStage}</h3><div class="bracket-wrapper"><div class="bracket"><div class="bracket-col"><h4>QF</h4>${season.bracket.qf.map(m => drawBracketMatch(m)).join('')}</div><div class="bracket-col"><h4>SF</h4>${season.bracket.sf.map(m => drawBracketMatch(m)).join('')}</div><div class="bracket-col"><h4>FINALS</h4>${season.bracket.finals.map(m => drawBracketMatch(m)).join('')}</div></div></div>`;

    const btnPlay = document.getElementById("btn-next-match"), containerBtns = document.getElementById("playoff-action-btns");
    if (season.champion) { btnPlay.style.display = "none"; containerBtns.style.display = "none"; return; }

    let isPlayerStillInTournament = season.playoffMatchups.some(m => m.t1 === teamName || m.t2 === teamName);
    let myMatch = season.playoffMatchups.find(m => (m.t1 === teamName || m.t2 === teamName) && !m.finished);
    
    if (myMatch) {
        btnPlay.style.display = "inline-block"; containerBtns.style.display = "none"; btnPlay.innerText = i18n[currentLang].btnNextMatch;
        btnPlay.onclick = () => {
            season.playoffMatchups.filter(m => m !== myMatch && !m.finished).forEach(aiMatch => {
                let aiT1 = season.teams.find(t => t.teamName === aiMatch.t1), aiT2 = season.teams.find(t => t.teamName === aiMatch.t2); let res = fastSimulateAIMatch(aiT1, aiT2);
                if(res.s1 === 3) aiMatch.wins1++; else aiMatch.wins2++; if(aiMatch.wins1 === 2 || aiMatch.wins2 === 2) aiMatch.finished = true;
            });
            let oppName = myMatch.t1 === teamName ? myMatch.t2 : myMatch.t1; season.myCurrentOpponent = season.teams.find(t => t.teamName === oppName); document.getElementById("season-hub-modal").style.display = "none"; setupPlayerMatch(season.myCurrentOpponent);
        };
    } else if (isPlayerStillInTournament) {
        btnPlay.style.display = "inline-block"; containerBtns.style.display = "none"; btnPlay.innerText = "Symulacja fazy ➔";
        btnPlay.onclick = () => {
            season.playoffMatchups.filter(m => !m.finished).forEach(aiMatch => {
                let aiT1 = season.teams.find(t => t.teamName === aiMatch.t1), aiT2 = season.teams.find(t => t.teamName === aiMatch.t2); let res = fastSimulateAIMatch(aiT1, aiT2);
                if(res.s1 === 3) aiMatch.wins1++; else aiMatch.wins2++; if(aiMatch.wins1 === 2 || aiMatch.wins2 === 2) aiMatch.finished = true;
            }); processPlayoffResult();
        };
    } else {
        btnPlay.style.display = "none"; containerBtns.style.display = "flex";
        containerBtns.innerHTML = `<button onclick="finishTournamentAI()" class="btn-action" style="background-color: #9b59b6;">${i18n[currentLang].btnSimToEnd}</button><button onclick="location.reload()" class="btn-action" style="background-color: #3498db;">${i18n[currentLang].sumBtnRestart}</button>`;
    }
}

function finishTournamentAI() {
    while(!season.champion) {
        season.playoffMatchups.filter(m => !m.finished).forEach(aiMatch => {
            let aiT1 = season.teams.find(t => t.teamName === aiMatch.t1), aiT2 = season.teams.find(t => t.teamName === aiMatch.t2);
            while(aiMatch.wins1 < 2 && aiMatch.wins2 < 2) { let res = fastSimulateAIMatch(aiT1, aiT2); if(res.s1 === 3) aiMatch.wins1++; else aiMatch.wins2++; }
            aiMatch.finished = true;
        });
        let allFinished = season.playoffMatchups.every(m => m.wins1 === 2 || m.wins2 === 2);
        if(allFinished) {
            season.playoffMatchups.forEach(m => { m.winner = m.wins1 === 2 ? m.t1 : m.t2; m.loser = m.wins1 === 2 ? m.t2 : m.t1; });
            if (season.playoffStage === "ĆWIERĆFINAŁY") {
                season.playoffStage = "PÓŁFINAŁY"; season.bracket.sf[0].t1 = season.bracket.qf[0].winner; season.bracket.sf[0].t2 = season.bracket.qf[1].winner; season.bracket.sf[1].t1 = season.bracket.qf[2].winner; season.bracket.sf[1].t2 = season.bracket.qf[3].winner; season.playoffMatchups = season.bracket.sf;
            } else if (season.playoffStage === "PÓŁFINAŁY") {
                season.playoffStage = "RUNDA FINAŁOWA"; season.bracket.finals[0].t1 = season.bracket.sf[0].loser; season.bracket.finals[0].t2 = season.bracket.sf[1].loser; season.bracket.finals[1].t1 = season.bracket.sf[0].winner; season.bracket.finals[1].t2 = season.bracket.sf[1].winner; season.playoffMatchups = season.bracket.finals;
            } else if (season.playoffStage === "RUNDA FINAŁOWA") { season.champion = season.bracket.finals[1].winner; }
        }
    }
    renderPlayoffHub(); setTimeout(() => { showSeasonSummary(season.champion); }, 1500);
}

function processPlayoffResult() {
    let myMatch = season.playoffMatchups.find(m => (m.t1 === teamName || m.t2 === teamName) && !m.finished);
    if (myMatch) {
        if (mySets === 3) { if(myMatch.t1 === teamName) myMatch.wins1++; else myMatch.wins2++; } else { if(myMatch.t1 === teamName) myMatch.wins2++; else myMatch.wins1++; }
        if (myMatch.wins1 === 2 || myMatch.wins2 === 2) { 
            myMatch.finished = true; myMatch.winner = myMatch.wins1 === 2 ? myMatch.t1 : myMatch.t2;
            if((myMatch.wins1 === 2 ? myMatch.t2 : myMatch.t1) === teamName) season.playerExitStage = season.playoffStage;
        }
    }
    let allFinished = season.playoffMatchups.every(m => m.wins1 === 2 || m.wins2 === 2);
    if (allFinished) {
        season.playoffMatchups.forEach(m => { m.winner = m.wins1 === 2 ? m.t1 : m.t2; m.loser = m.wins1 === 2 ? m.t2 : m.t1; });
        if (season.playoffStage === "ĆWIERĆFINAŁY") {
            season.playoffStage = "PÓŁFINAŁY"; season.bracket.sf[0].t1 = season.bracket.qf[0].winner; season.bracket.sf[0].t2 = season.bracket.qf[1].winner; season.bracket.sf[1].t1 = season.bracket.qf[2].winner; season.bracket.sf[1].t2 = season.bracket.qf[3].winner; season.playoffMatchups = season.bracket.sf;
        } else if (season.playoffStage === "PÓŁFINAŁY") {
            season.playoffStage = "RUNDA FINAŁOWA"; season.bracket.finals[0].t1 = season.bracket.sf[0].loser; season.bracket.finals[0].t2 = season.bracket.sf[1].loser; season.bracket.finals[1].t1 = season.bracket.sf[0].winner; season.bracket.finals[1].t2 = season.bracket.sf[1].winner; season.playoffMatchups = season.bracket.finals;
        } else if (season.playoffStage === "RUNDA FINAŁOWA") {
            season.champion = season.bracket.finals[1].winner; setTimeout(() => { showSeasonSummary(season.champion); }, 1500); return;
        }
    }
    showSeasonHub();
}

function showSeasonSummary(champion) {
    document.getElementById("season-hub-modal").style.display = "none"; document.getElementById("result-modal").style.display = "none"; document.getElementById("season-summary-modal").style.display = "flex";
    let t = i18n[currentLang];
    let grade = "C", color = "#e74c3c", desc = t.descBad;
    if (champion === teamName) { grade = "S+"; color = "#f1c40f"; desc = t.descWin; } else if (season.playerExitStage === "RUNDA FINAŁOWA") { grade = "A"; color = "#2ecc71"; desc = t.descFin; } else if (season.playerExitStage === "PÓŁFINAŁY") { grade = "B"; color = "#00a8ff"; desc = t.descSemi; }
    safeSet("manager-grade", grade); document.getElementById("manager-grade").style.color = color; safeSet("manager-desc", desc);
    
    const tbody = document.getElementById("season-stats-body"); tbody.innerHTML = "";
    Object.values(seasonStats).sort((a,b) => b.ptsTot - a.ptsTot).forEach(s => {
        let pGrade = "C", gColor = "#e74c3c";
        if (s.pos === "Libero") { let exc = s.przTot > 0 ? (s.przExc / s.przTot) * 100 * 0.4 : 0; if(exc > 30) pGrade = "S"; else if(exc > 22) pGrade = "A"; else if(exc > 15) pGrade = "B"; } 
        else if (s.pos === "Rozgrywający") { if(s.wl > 35) pGrade = "S"; else if(s.wl > 20) pGrade = "A"; else if(s.wl > 5) pGrade = "B"; } 
        else if (s.pos.includes("Środkowy")) { if(s.ptsTot > 35) pGrade = "S"; else if(s.ptsTot > 25) pGrade = "A"; else if(s.ptsTot > 12) pGrade = "B"; } 
        else { if(s.ptsTot > 60) pGrade = "S"; else if(s.ptsTot > 40) pGrade = "A"; else if(s.ptsTot > 25) pGrade = "B"; }
        if(pGrade === "S") gColor = "#f1c40f"; if(pGrade === "A") gColor = "#2ecc71"; if(pGrade === "B") gColor = "#00a8ff";

        let pName = getPosName(s.pos, currentLang);
        let przPozPct = s.przTot > 0 ? Math.round((s.przPoz / s.przTot) * 100 * 0.65) + "%" : "-"; let przExcPct = s.przTot > 0 ? Math.round((s.przExc / s.przTot) * 100 * 0.4) + "%" : "-"; let atkExcPct = s.atkTot > 0 ? Math.round((s.atkPkt / s.atkTot) * 100) + "%" : "-"; let atkEffPct = s.atkTot > 0 ? Math.round(((s.atkPkt - s.atkErr - s.atkBlk) / s.atkTot) * 100) + "%" : "-";
        
        tbody.innerHTML += `<tr>
            <td style="text-align: left; font-weight: bold;">${s.name} <br><span style="font-size:0.7em; color:#bdc3c7;">${pName}</span></td>
            <td style="color:${gColor}; font-weight:bold; font-size:1.4em;">${pGrade}</td>
            <td><strong style="color:white; font-size:1.2em;">${s.ptsTot}</strong></td>
            <td><strong style="color:#00a8ff;">${s.srvAce}</strong> | <span style="color:#e74c3c;">${s.srvErr}</span></td>
            <td><span style="color:#bdc3c7;">${s.przTot} | ${s.przErr}</span> | <strong style="color:#a29bfe;">${przPozPct}</strong> | <strong style="color:#2ecc71;">${przExcPct}</strong></td>
            <td><strong style="color:#2ecc71;">${s.atkPkt}</strong> | ${atkExcPct} | <strong>${atkEffPct}</strong></td>
            <td><strong style="color:#e67e22; font-size:1.2em;">${s.blkPkt}</strong></td>
        </tr>`;
    });
}